public static String getExtension(final Path path) {
        // TODO Use Commons IO 2.17.0
        if (path == null) {
            return null;
        }
        final Path fileName = path.getFileName();
        return fileName != null ? FilenameUtils.getExtension(fileName.toString()) : null;
    }

